Bash(cd "C:\\Code\\music_app\\music_app\\packages\\api" && node -e "
const Database = require\('better-sqlite3'\);
const db = new Database\('./data/jukebox.db'\);

try {
    const trendingSongs = db.prepare\(\\`
        SELECT youtube_id, channel_name, title, thumbnail, duration,
               AVG\(s.vote_score\) as avg_vote_score,
               COUNT\(*\) as play_count,
               GROUP_CONCAT\(DISTINCT r.name, ', ' LIMIT 3\) as popular_rooms
        FROM songs s
        LEFT JOIN rooms r ON s.room_id = r.id
        GROUP BY youtube_id, channel_name, title, thumbnail, duration
        ORDER BY avg_vote_score DESC, play_count DESC
        LIMIT 5
    \\`\).all\(\);

    console.log\('Trending songs found:', trendingSongs.length\);
    console.log\('First song:', trendingSongs[0]\);
} catch \(error\) {
    console.error\('Error:', error.message\);
}
")

